// Scoped to .cc-pproem-alerts. Generated by microsites/_dversion-build.mjs.
(function () {
  // Use window.document explicitly here — declaring  const document
  // = …  later in this scope hoists the binding to the top of the
  // function as TDZ, so plain  document.querySelector  on this line
  // would throw "Cannot access 'document' before initialization".
  const ROOT = window.document.querySelector('.cc-pproem-alerts');
  if (!ROOT) return;

  // Re-bind document.* lookups to resolve against the partial root,
  // so IDs and class selectors can't collide with the host Drupal page.
  const document = new Proxy(window.document, {
    get(target, prop) {
      if (prop === 'getElementById') return (id) => ROOT.querySelector('#' + CSS.escape(id));
      if (prop === 'querySelector') return (sel) => ROOT.querySelector(sel);
      if (prop === 'querySelectorAll') return (sel) => ROOT.querySelectorAll(sel);
      const v = target[prop];
      return typeof v === 'function' ? v.bind(target) : v;
    },
  });

// ============ Live data sources ============
  // PPROEM publishes hazard zones and road closures as ArcGIS feature
  // services (the same ones their public viewer at experience.arcgis.com
  // reads). El Paso County publishes a public parcels MapServer. ArcGIS
  // World Geocoder turns user-typed addresses into lat/long. All four
  // are CORS-enabled and free to use anonymously from a browser.
  //
  // PPROEM's other alert mechanism — Peak Alerts via Everbridge — is
  // PUSH-only (subscribers receive SMS/email). It has no public pull
  // API. The "Get alerts for this address" button below routes users
  // there to subscribe; the page itself reads its zone status from the
  // ArcGIS feed because that's the authoritative machine-readable
  // source PPROEM exposes.
  const SOURCES = {
    hazards:      'https://services3.arcgis.com/4RbSpZqACDsi1hHk/arcgis/rest/services/Hazard_Boundary/FeatureServer/0',
    roadClosures: 'https://services3.arcgis.com/4RbSpZqACDsi1hHk/arcgis/rest/services/Road_Closure/FeatureServer/0',
    parcels:      'https://gisservices.elpasoco.com/arcgis2/rest/services/HubPublic/Parcels/MapServer/0',
    geocoder:     'https://geocode.arcgis.com/arcgis/rest/services/World/GeocodeServer/findAddressCandidates',
    peakAlerts:   'https://member.everbridge.net/1772417038942752/new'
  };
  const REFRESH_MS = 5 * 60 * 1000;
  // Bounding box for El Paso County (approx). Used to constrain the
  // geocoder so "123 Main St" doesn't return a hit in another state.
  const EL_PASO_BBOX = '-105.07,38.51,-104.02,39.13';

  // ============ Mock fallback (used if live fetch fails) ============
  const MOCK_ZONES = [
    {
      id: 'EPC-S012',
      name: 'Lorson Ranch / Bradley',
      status: 'evac',
      statusLabel: 'Evacuation Order',
      desc: 'Wildfire approaching from the south. Residents must leave immediately via Powers Blvd north.',
      coords: [
        [38.745, -104.720],[38.745, -104.660],[38.778, -104.660],[38.778, -104.720]
      ],
      center: [38.762, -104.690],
      issued: '13:42',
      affected: 4800
    },
    {
      id: 'EPC-N004',
      name: 'Black Forest North',
      status: 'warning',
      statusLabel: 'Evacuation Warning',
      desc: 'Be prepared to leave on short notice. Pack go-bags, fuel vehicles, monitor conditions.',
      coords: [
        [38.985, -104.730],[38.985, -104.660],[39.030, -104.660],[39.030, -104.730]
      ],
      center: [39.007, -104.695],
      issued: '14:15',
      affected: 7200
    },
    {
      id: 'EPC-E021',
      name: 'Falcon West',
      status: 'advisory',
      statusLabel: 'Air Quality Advisory',
      desc: 'Heavy smoke from southern fire. Sensitive groups should remain indoors with windows closed.',
      coords: [
        [38.920, -104.640],[38.920, -104.580],[38.965, -104.580],[38.965, -104.640]
      ],
      center: [38.942, -104.610],
      issued: '14:30',
      affected: 2200
    },
    {
      id: 'EPC-C001',
      name: 'Downtown Colorado Springs',
      status: 'clear',
      statusLabel: 'No Active Alerts',
      desc: 'No emergency conditions at this time.',
      coords: [
        [38.815, -104.840],[38.815, -104.800],[38.855, -104.800],[38.855, -104.840]
      ],
      center: [38.833, -104.821],
      issued: null,
      affected: 0
    },
    {
      id: 'EPC-W007',
      name: 'Manitou Springs',
      status: 'clear',
      statusLabel: 'No Active Alerts',
      desc: 'No emergency conditions at this time.',
      coords: [
        [38.840, -104.940],[38.840, -104.895],[38.875, -104.895],[38.875, -104.940]
      ],
      center: [38.857, -104.917],
      issued: null,
      affected: 0
    },
    {
      id: 'EPC-N009',
      name: 'Monument',
      status: 'clear',
      statusLabel: 'No Active Alerts',
      desc: 'No emergency conditions at this time.',
      coords: [
        [39.075, -104.900],[39.075, -104.845],[39.110, -104.845],[39.110, -104.900]
      ],
      center: [39.091, -104.872],
      issued: null,
      affected: 0
    }
  ];

  // Hot-replaced once live data lands.
  let zones = MOCK_ZONES.slice();
  let isLiveData = false;

  const statusColors = {
    evac: '#A4161A',
    warning: '#C2410C',
    advisory: '#A37000',
    clear: '#2D7A4E'
  };

  let currentSearchedAddress = null;

  // ============ Live fetchers ============

  // Map ArcGIS Hazard_Boundary BoundaryType + Status onto the four
  // display tiers the rest of the page understands. Inactive features
  // are filtered out before this is called, but we map them anyway in
  // case PPROEM adds a "cleared but recent" status.
  function classifyHazard(boundaryType, status) {
    const t = (boundaryType || '').toLowerCase();
    const s = (status || '').toLowerCase();
    if (s.includes('inactive') || s.includes('cleared')) return 'clear';
    if (t.includes('evacuation order') || /\bmandatory\b/.test(t) || t === 'evacuation') return 'evac';
    if (t.includes('warning') || t.includes('pre-evac')) return 'warning';
    if (t.includes('advisory') || t.includes('shelter') || t.includes('air quality')) return 'advisory';
    // Fire boundaries with no other classifier are treated as warnings
    // (the fire perimeter itself isn't an evacuation order, but residents
    // inside should be on alert).
    if (t.includes('fire')) return 'warning';
    return 'advisory';
  }

  function statusLabelFor(status) {
    return ({
      evac: 'Evacuation Order',
      warning: 'Evacuation Warning',
      advisory: 'Advisory',
      clear: 'No Active Alerts'
    })[status] || 'Active';
  }

  // GeoJSON polygon coordinates are [lng, lat]; Leaflet wants [lat, lng].
  function ringToLeaflet(ring) {
    return ring.map(([lng, lat]) => [lat, lng]);
  }

  function centroidOf(ring) {
    if (!ring.length) return [38.835, -104.821];
    let lat = 0, lng = 0;
    for (const [a, b] of ring) { lat += a; lng += b; }
    return [lat / ring.length, lng / ring.length];
  }

  function featureToZone(feat) {
    const a = feat.properties || feat.attributes || {};
    const geom = feat.geometry;
    if (!geom) return null;
    let rings;
    if (geom.type === 'Polygon') {
      rings = geom.coordinates;
    } else if (geom.type === 'MultiPolygon') {
      rings = geom.coordinates.flat();
    } else if (geom.rings) {
      // Esri JSON (when f=json instead of f=geojson)
      rings = geom.rings;
    } else {
      return null;
    }
    if (!rings || !rings.length) return null;
    const outer = ringToLeaflet(rings[0]);
    const status = classifyHazard(a.BoundaryType, a.Status);
    const issuedAt = a.EditDate || a.CreationDate;
    return {
      id: 'EPC-' + (a.OBJECTID ?? Math.floor(Math.random() * 10000)),
      name: a.Comments || a.Notes || a.Event || a.BoundaryType || 'Hazard area',
      status,
      statusLabel: statusLabelFor(status),
      desc: a.Notes || a.Comments
        || (a.Event ? `${a.BoundaryType || 'Hazard'} — ${a.Event}. Monitor PPROEM Peak Alerts for current guidance.`
                    : `${a.BoundaryType || 'Hazard'} active. Monitor PPROEM Peak Alerts for current guidance.`),
      coords: outer,
      center: centroidOf(outer),
      issued: issuedAt ? new Date(issuedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : null,
      affected: Math.round(a.Acres || 0),
      raw: a
    };
  }

  async function fetchActiveHazards() {
    // f=geojson is the cleanest output format; falls back to f=json
    // automatically if the server doesn't support it.
    const params = new URLSearchParams({
      where: "Status='Active'",
      outFields: '*',
      returnGeometry: 'true',
      f: 'geojson'
    });
    const res = await fetch(`${SOURCES.hazards}/query?${params}`);
    if (!res.ok) throw new Error(`hazard fetch ${res.status}`);
    const data = await res.json();
    const features = data.features || [];
    return features.map(featureToZone).filter(Boolean);
  }

  async function geocodeAddress(query) {
    const params = new URLSearchParams({
      singleLine: query,
      searchExtent: EL_PASO_BBOX,
      countryCode: 'USA',
      outFields: 'Match_addr,Addr_type,StAddr,City,Postal',
      forStorage: 'false',
      maxLocations: '1',
      f: 'json'
    });
    const res = await fetch(`${SOURCES.geocoder}?${params}`);
    if (!res.ok) throw new Error(`geocode ${res.status}`);
    const data = await res.json();
    const cand = (data.candidates || [])[0];
    if (!cand || cand.score < 80) return null;
    return {
      address: cand.attributes.StAddr || cand.attributes.Match_addr,
      city: [cand.attributes.City, cand.attributes.Postal].filter(Boolean).join(' '),
      coords: [cand.location.y, cand.location.x],
      _matchAddr: cand.attributes.Match_addr
    };
  }

  async function lookupParcelAt(lat, lng) {
    const params = new URLSearchParams({
      geometry: `${lng},${lat}`,
      geometryType: 'esriGeometryPoint',
      inSR: '4326',
      spatialRel: 'esriSpatialRelIntersects',
      outFields: 'PARCEL,HYPERLINK',
      returnGeometry: 'false',
      f: 'json'
    });
    const res = await fetch(`${SOURCES.parcels}/query?${params}`);
    if (!res.ok) throw new Error(`parcel ${res.status}`);
    const data = await res.json();
    const parcel = (data.features || [])[0];
    return parcel ? parcel.attributes : null;
  }

  // Ray-casting point-in-polygon. Returns the most-severe matching zone.
  function findZoneForPoint(lat, lng) {
    const severity = { evac: 4, warning: 3, advisory: 2, clear: 1 };
    let best = null;
    for (const z of zones) {
      let inside = false;
      const ring = z.coords;
      for (let i = 0, j = ring.length - 1; i < ring.length; j = i++) {
        const [iy, ix] = ring[i];
        const [jy, jx] = ring[j];
        if (((iy > lat) !== (jy > lat)) &&
            (lng < (jx - ix) * (lat - iy) / (jy - iy) + ix)) {
          inside = !inside;
        }
      }
      if (inside && (!best || severity[z.status] > severity[best.status])) best = z;
    }
    return best;
  }

  // Synthesize a "no active alerts" zone for addresses outside any
  // active hazard boundary — keeps renderResult happy.
  function clearZoneFor(addr) {
    return {
      id: 'EPC-CLEAR',
      name: addr.city || 'Outside active zones',
      status: 'clear',
      statusLabel: 'No Active Alerts',
      desc: 'No emergency conditions at this address.',
      coords: [],
      center: addr.coords,
      issued: null,
      affected: 0
    };
  }

  // ============ Map Setup ============
  const map = L.map('map', {
    zoomControl: true,
    scrollWheelZoom: false
  }).setView([38.870, -104.790], 10);

  L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
    attribution: '&copy; OpenStreetMap contributors &copy; CARTO',
    subdomains: 'abcd',
    maxZoom: 19
  }).addTo(map);

  const zonePolygons = {};

  function clearPolygons() {
    for (const k of Object.keys(zonePolygons)) {
      map.removeLayer(zonePolygons[k]);
      delete zonePolygons[k];
    }
  }

  function drawZones() {
    clearPolygons();
    zones.forEach(zone => {
      if (!zone.coords || !zone.coords.length) return;
      const polygon = L.polygon(zone.coords, {
        color: statusColors[zone.status],
        fillColor: statusColors[zone.status],
        fillOpacity: zone.status === 'clear' ? 0.15 : 0.35,
        weight: 2,
        opacity: zone.status === 'clear' ? 0.5 : 0.9
      }).addTo(map);

      polygon.bindPopup(`
        <div class="popup-title">${zone.name}</div>
        <div class="popup-id">${zone.id}</div>
        <div><strong>${zone.statusLabel}</strong></div>
        <div style="margin-top: 6px; color: var(--text-muted);">${zone.desc}</div>
      `);

      polygon.on('click', () => highlightZone(zone.id));
      zonePolygons[zone.id] = polygon;
    });
  }

  drawZones();

  // ============ Zone List ============
  function renderZoneList(filter = 'active') {
    const list = document.getElementById('zone-list');
    const filteredZones = filter === 'active'
      ? zones.filter(z => z.status !== 'clear')
      : zones;

    list.innerHTML = filteredZones.map(zone => `
      <button type="button" class="zone-card" data-zone-id="${zone.id}" onclick="focusZone('${zone.id}')" aria-label="${zone.name}, ${zone.statusLabel}. Show on map.">
        <div class="zone-card-header">
          <div>
            <div class="zone-card-name">${zone.name}</div>
            <div class="zone-card-id">${zone.id}</div>
          </div>
          <span class="status-badge status-${zone.status}">${zone.statusLabel}</span>
        </div>
        <div class="zone-card-desc">${zone.desc}</div>
        ${zone.issued ? `<div class="zone-card-meta">
          <span>Issued ${zone.issued}</span>
          <span>·</span>
          <span>~${zone.affected.toLocaleString()} residents</span>
        </div>` : ''}
      </button>
    `).join('');
  }

  renderZoneList('active');

  function switchTab(event, tab) {
    // Roving-tabindex pattern (per ARIA Authoring Practices) — only
    // the currently-selected tab is in the page tab order; the others
    // are reachable via Arrow keys (see onTabKeydown below).
    document.querySelectorAll('.tab').forEach(t => {
      t.classList.remove('active');
      t.setAttribute('aria-selected', 'false');
      t.setAttribute('tabindex', '-1');
    });
    event.currentTarget.classList.add('active');
    event.currentTarget.setAttribute('aria-selected', 'true');
    event.currentTarget.setAttribute('tabindex', '0');
    // Re-point the tabpanel's aria-labelledby at the new tab so SR
    // users hear the right context when they enter the panel.
    const panel = document.getElementById('zone-list');
    if (panel) panel.setAttribute('aria-labelledby', event.currentTarget.id);
    renderZoneList(tab);
  }

  // Arrow-key navigation across the tablist. Left/Right and Home/End
  // move focus and activate (per the "automatic activation" pattern,
  // which is appropriate here since switching the tab has no cost
  // beyond a re-render).
  function onTabKeydown(event) {
    const keys = ['ArrowLeft', 'ArrowRight', 'Home', 'End'];
    if (!keys.includes(event.key)) return;
    event.preventDefault();
    const tabs = Array.from(document.querySelectorAll('[role="tab"]'));
    const idx = tabs.indexOf(event.currentTarget);
    let next;
    if (event.key === 'ArrowRight') next = tabs[(idx + 1) % tabs.length];
    else if (event.key === 'ArrowLeft') next = tabs[(idx - 1 + tabs.length) % tabs.length];
    else if (event.key === 'Home') next = tabs[0];
    else if (event.key === 'End') next = tabs[tabs.length - 1];
    if (!next) return;
    next.focus();
    next.click();
  }

  function focusZone(zoneId) {
    const zone = zones.find(z => z.id === zoneId);
    if (!zone) return;
    map.setView(zone.center, 12, { animate: true });
    zonePolygons[zoneId].openPopup();
    highlightZone(zoneId);
  }

  function highlightZone(zoneId) {
    document.querySelectorAll('.zone-card').forEach(card => {
      card.classList.toggle('highlighted', card.dataset.zoneId === zoneId);
    });
  }

  // ============ Search ============
  // Live pipeline:  ArcGIS World Geocoder → EPC Parcels MapServer →
  // point-in-polygon against active hazard zones.
  //
  // Demo fallbacks remain for the three pinned addresses on the
  // chiclet bar; these keep the page demo-able when the network is
  // offline or rate-limited and let users see all three guidance
  // tiers (evac / warning / clear) without waiting for a real
  // hazard event.
  const DEMO_ADDRESSES = {
    lorson:      { address: '4720 Lorson Ranch Pkwy',  city: 'Colorado Springs, CO 80925', parcel: '6401303008', zoneId: 'EPC-S012', coords: [38.762, -104.690] },
    blackforest: { address: '8901 Black Forest Rd',     city: 'Colorado Springs, CO 80908', parcel: '5208104017', zoneId: 'EPC-N004', coords: [39.007, -104.695] },
    downtown:    { address: '123 N Tejon St',           city: 'Colorado Springs, CO 80903', parcel: '7402211005', zoneId: 'EPC-C001', coords: [38.835, -104.821] }
  };

  function setSearchBusy(busy) {
    const form = document.querySelector('.search-form');
    if (form) form.classList.toggle('busy', busy);
  }

  async function handleSearch(event) {
    event.preventDefault();
    const value = document.getElementById('address-input').value.trim();
    if (!value) return;
    setSearchBusy(true);
    try {
      // 1. Geocode the typed address.
      const geo = await geocodeAddress(value);
      if (!geo) {
        renderSearchError(`We couldn't find "${value}" in El Paso County. Try a full street address — number, street, city.`);
        return;
      }
      // 2. Look up parcel polygon at the geocoded point.
      let parcel = null;
      try { parcel = await lookupParcelAt(geo.coords[0], geo.coords[1]); } catch (e) { /* parcel lookup is optional */ }
      const addr = {
        address: geo.address,
        city: geo.city,
        parcel: parcel ? parcel.PARCEL : '—',
        parcelLink: parcel ? parcel.HYPERLINK : null,
        coords: geo.coords
      };
      currentSearchedAddress = addr;
      // 3. Find the active hazard zone covering this point (if any).
      const zone = findZoneForPoint(geo.coords[0], geo.coords[1]) || clearZoneFor(addr);

      document.getElementById('address-input').value = addr.address;
      map.setView(addr.coords, 14, { animate: true });
      if (zonePolygons[zone.id]) zonePolygons[zone.id].openPopup();
      highlightZone(zone.id);
      renderResult(addr, zone);
      setTimeout(() => {
        document.getElementById('result-section').scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 200);
    } catch (err) {
      console.warn('Search failed, falling back to demo:', err);
      renderSearchError("Live address lookup is unavailable right now. Try one of the demo addresses below.");
    } finally {
      setSearchBusy(false);
    }
  }

  function renderSearchError(msg) {
    const sec = document.getElementById('result-section');
    sec.classList.add('active');
    sec.innerHTML = `
      <div class="result-card">
        <div class="result-status-block warning">
          <div class="result-status-headline">Search unavailable</div>
          <div class="result-guidance"><p>${msg}</p></div>
        </div>
      </div>`;
  }

  function demoSearch(key) {
    const addr = DEMO_ADDRESSES[key];
    if (!addr) return;
    // In demo mode the canned address is paired with a mock zone; in
    // live mode the same address is geocoded and tested against the
    // current live zones (which may produce a different status).
    if (isLiveData) {
      document.getElementById('address-input').value = addr.address;
      handleSearch({ preventDefault() {} });
      return;
    }
    const zone = zones.find(z => z.id === addr.zoneId) || clearZoneFor(addr);
    currentSearchedAddress = addr;
    document.getElementById('address-input').value = addr.address;
    map.setView(addr.coords, 13, { animate: true });
    if (zonePolygons[zone.id]) zonePolygons[zone.id].openPopup();
    highlightZone(zone.id);
    renderResult(addr, zone);
    setTimeout(() => {
      document.getElementById('result-section').scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 200);
  }

  function renderResult(addr, zone) {
    const guidance = {
      evac: {
        headline: 'EVACUATION ORDER — Leave now.',
        body: `<p><strong>Your address is inside an active evacuation zone.</strong> Leave immediately. Do not wait for further instruction.</p>
               <p><strong>Route:</strong> Take Powers Boulevard <em>north</em> toward Briargate. Avoid Highway 115 — emergency vehicles only.</p>
               <p><strong>Bring:</strong> Identification, medications, pets, phone charger, important documents. Leave everything else.</p>
               <p><strong>Shelter:</strong> American Red Cross shelter open at <strong>Sand Creek High School</strong>, 7005 N Carefree Cir. Pet-friendly.</p>`,
        cls: 'evac'
      },
      warning: {
        headline: 'EVACUATION WARNING — Be ready to leave.',
        body: `<p><strong>Your address is in an evacuation warning area.</strong> Conditions could change rapidly. Prepare to leave on short notice.</p>
               <p><strong>Now:</strong> Pack go-bags, gather medications and documents, fuel your vehicle, move pets to carriers.</p>
               <p><strong>Plan your route:</strong> Primary exit is Highway 83 south. Identify a backup route.</p>
               <p><strong>Stay informed:</strong> Subscribe below for immediate notification if this is upgraded to an evacuation order.</p>`,
        cls: 'warning'
      },
      advisory: {
        headline: 'AIR QUALITY ADVISORY in effect.',
        body: `<p>Heavy smoke from a wildfire to the south is affecting air quality at your address.</p>
               <p><strong>Sensitive groups</strong> (children, elderly, those with respiratory conditions) should stay indoors with windows closed.</p>
               <p><strong>Run HVAC on recirculate.</strong> Avoid outdoor exercise. N95 masks recommended if you must be outside.</p>`,
        cls: 'warning'
      },
      clear: {
        headline: 'No active alerts at this address.',
        body: `<p>Your address is not currently under any evacuation order, warning, or advisory.</p>
               <p>Conditions are normal as of <strong>02:47 PM MST</strong>. We'll notify you immediately if anything changes — subscribe below to make sure you don't miss it.</p>`,
        cls: 'clear'
      }
    };

    const g = guidance[zone.status];

    const records = zone.status === 'evac' ? [
      { type: 'Evacuation Order', icon: 'doc', title: 'Order EVAC-2026-0047 — Lorson Ranch Mandatory Evacuation', meta: 'PDF · Issued 13:42 · El Paso County Sheriff' },
      { type: 'Road Closure', icon: 'cone', title: 'Highway 115 closed southbound from Powers to Penrose', meta: 'Permit ROAD-2026-1108 · Active' },
      { type: 'Shelter Activation', icon: 'home', title: 'Sand Creek High School emergency shelter opened', meta: 'Activation 14:00 · Red Cross + EPC' },
      { type: 'Meeting Item', icon: 'meeting', title: 'BoCC Emergency Session — Wildfire Response', meta: 'Today 16:00 · Item 3 on agenda' }
    ] : zone.status === 'warning' ? [
      { type: 'Warning Notice', icon: 'doc', title: 'Notice EVAC-2026-0048 — Black Forest North Warning', meta: 'PDF · Issued 14:15 · El Paso County OEM' },
      { type: 'Fire Permit', icon: 'doc', title: 'Burn permits suspended countywide through Sunday', meta: 'Order FIRE-2026-0019 · Active' },
      { type: 'Meeting Item', icon: 'meeting', title: 'Black Forest Fire Mitigation — recurring discussion', meta: 'Last covered 2026-04-22 BoCC' }
    ] : zone.status === 'advisory' ? [
      { type: 'Advisory', icon: 'doc', title: 'Air Quality Advisory AQ-2026-0033', meta: 'PDF · Issued 14:30 · CDPHE + EPC Health' }
    ] : [
      { type: 'Property Record', icon: 'home', title: 'Parcel ' + addr.parcel + ' — Single family residential', meta: 'El Paso County Assessor · Last updated 2025-09-12' },
      { type: 'Permit History', icon: 'doc', title: 'No active permits on this parcel', meta: 'Pikes Peak Regional Building Department' },
      { type: 'Mill Levy', icon: 'doc', title: 'Total mill levy 2026: 78.412', meta: 'Includes county, school, fire, library' }
    ];

    const iconSvg = {
      doc: '<path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/>',
      cone: '<path d="m16.5 18 1.4-7H6.1L7.5 18"/><path d="M2 22h20"/><path d="m12 2 4 9H8z"/>',
      home: '<path d="m3 9 9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/>',
      meeting: '<rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/>'
    };

    document.getElementById('result-section').classList.add('active');
    document.getElementById('result-section').innerHTML = `
      <div class="result-card">
        <div class="result-header">
          <div class="result-address">
            <div class="result-address-label">Address</div>
            <h2>${addr.address}</h2>
            <div class="result-meta">
              <span>${addr.city}</span>
              <span>·</span>
              <span>Parcel <strong>${addr.parcel}</strong></span>
              <span>·</span>
              <span>Zone <strong>${zone.id}</strong></span>
            </div>
          </div>
          <span class="status-badge status-${zone.status}" style="font-size: 13px; padding: 6px 14px;">${zone.statusLabel}</span>
        </div>
        <div class="result-status-block ${g.cls}">
          <div class="result-status-headline">${g.headline}</div>
          <div class="result-guidance">${g.body}</div>
        </div>
        <div class="result-actions">
          <button type="button" class="btn-primary" onclick="openSubscribe()">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><path d="M6 8a6 6 0 0 1 12 0c0 7 3 9 3 9H3s3-2 3-9"/><path d="M10.3 21a1.94 1.94 0 0 0 3.4 0"/></svg>
            Get alerts for this address
          </button>
          <button type="button" class="btn-secondary" aria-label="Share this address result">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><path d="M4 12v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-8"/><polyline points="16 6 12 2 8 6"/><line x1="12" y1="2" x2="12" y2="15"/></svg>
            Share
          </button>
          <button type="button" class="btn-secondary" onclick="window.print()" aria-label="Print this address result">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><polyline points="6 9 6 2 18 2 18 9"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
            Print
          </button>
        </div>
        <div class="records-section">
          <h3>Connected records</h3>
          <p class="records-subhead">Every document, permit, meeting item, and notice attached to this parcel — searchable, in chronological order.</p>
          <div class="records-grid">
            ${records.map(r => `
              <a href="#" class="record-item">
                <div class="record-item-type">
                  <svg class="record-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">${iconSvg[r.icon]}</svg>
                  ${r.type}
                </div>
                <div class="record-item-title">${r.title}</div>
                <div class="record-item-meta">${r.meta}</div>
              </a>
            `).join('')}
          </div>
        </div>
      </div>
    `;
  }

  // ============ Subscribe Modal ============
  // Focus management is critical for ADA: trap Tab inside the modal
  // while it's open, return focus to the element that opened it.
  let _modalLastFocus = null;

  function openSubscribe() {
    const binding = document.getElementById('modal-address-binding');
    if (currentSearchedAddress) {
      binding.querySelector('.address-binding-value').textContent =
        currentSearchedAddress.address + ' · Parcel ' + currentSearchedAddress.parcel;
    } else {
      binding.querySelector('.address-binding-value').textContent = 'All of El Paso County (no address selected)';
    }
    _modalLastFocus = document.activeElement;
    const modal = document.getElementById('subscribe-modal');
    modal.classList.add('open');
    modal.removeAttribute('aria-hidden');
    // Lock background scroll so Tab can't escape into the page below.
    document.body.style.overflow = 'hidden';
    setTimeout(() => document.getElementById('email-input').focus(), 100);
  }

  function closeSubscribe() {
    const modal = document.getElementById('subscribe-modal');
    modal.classList.remove('open');
    modal.setAttribute('aria-hidden', 'true');
    document.body.style.overflow = '';
    // Return focus to whatever opened the modal so keyboard users
    // don't get dumped at the top of the page.
    if (_modalLastFocus && typeof _modalLastFocus.focus === 'function') {
      _modalLastFocus.focus();
    }
    _modalLastFocus = null;
  }

  // Tab focus trap — keeps focus inside .modal while the modal is open.
  document.addEventListener('keydown', function (e) {
    if (e.key !== 'Tab') return;
    const modal = document.getElementById('subscribe-modal');
    if (!modal || !modal.classList.contains('open')) return;
    const focusable = modal.querySelectorAll(
      'a[href], button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])'
    );
    if (!focusable.length) return;
    const first = focusable[0];
    const last = focusable[focusable.length - 1];
    if (e.shiftKey && document.activeElement === first) {
      e.preventDefault();
      last.focus();
    } else if (!e.shiftKey && document.activeElement === last) {
      e.preventDefault();
      first.focus();
    }
  });

  function handleSubscribe() {
    const email = document.getElementById('email-input').value;
    if (!email) {
      document.getElementById('email-input').focus();
      return;
    }
    closeSubscribe();
    alert('Subscribed! In production this would write to your alerts database (replacing the Everbridge dependency).');
  }

  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') closeSubscribe();
  });

  // ============ Bootstrap (live data on load + auto-refresh) ============
  // Status banner — a small strip just under the topbar that shows
  // whether the zones came from PPROEM's live ArcGIS feed or from the
  // mock fallback. Inserted only if the host markup hasn't already
  // provided one (so the same script can run in standalone, .njk, and
  // dversion contexts without duplicating the banner).
  function ensureStatusBanner() {
    let bar = document.getElementById('data-status-bar');
    if (bar) return bar;
    bar = document.createElement('div');
    bar.id = 'data-status-bar';
    bar.style.cssText = 'padding:8px 16px;font-size:13px;border-bottom:1px solid var(--border, #E5DDD0);background:var(--surface, #fff);color:var(--text-muted, #5C6573);display:flex;gap:12px;align-items:center;flex-wrap:wrap';
    bar.setAttribute('role', 'status');
    bar.setAttribute('aria-live', 'polite');
    const main = document.getElementById('main-content') || document.querySelector('.alerts-main, main');
    if (main && main.parentNode) main.parentNode.insertBefore(bar, main);
    return bar;
  }

  function setDataStatus(state, count) {
    const bar = ensureStatusBanner();
    const dot = (color) => `<span aria-hidden="true" style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${color};margin-right:6px;vertical-align:middle"></span>`;
    if (state === 'loading') {
      bar.innerHTML = `${dot('#A37000')}Loading current alerts from PPROEM…`;
    } else if (state === 'live') {
      bar.innerHTML = `${dot('#2D7A4E')}<strong>Live data</strong> — ${count} active hazard ${count === 1 ? 'zone' : 'zones'} from PPROEM. Last refreshed ${new Date().toLocaleTimeString([], {hour: '2-digit', minute: '2-digit'})}. Auto-refreshes every 5 minutes.`;
    } else if (state === 'live-empty') {
      bar.innerHTML = `${dot('#2D7A4E')}<strong>Live data</strong> — no active hazard zones in El Paso County. Last checked ${new Date().toLocaleTimeString([], {hour: '2-digit', minute: '2-digit'})}.`;
    } else if (state === 'demo') {
      bar.innerHTML = `${dot('#A4161A')}<strong>Demo data</strong> — couldn't reach the live PPROEM hazard feed. Showing mock zones. <a href="https://pproem.com/alerts" target="_blank" rel="noopener" style="color:inherit;text-decoration:underline">Check the official PPROEM alerts page</a> for current information.`;
    }
  }

  async function loadLiveZones() {
    try {
      const live = await fetchActiveHazards();
      if (live && live.length) {
        zones = live;
        isLiveData = true;
        drawZones();
        renderZoneList('active');
        setDataStatus('live', live.length);
      } else {
        // Endpoint returned 0 active zones — that's a normal state, not
        // an error. Use a clean "no active alerts" placeholder so the
        // rendering stays consistent.
        zones = [{
          id: 'EPC-NONE',
          name: 'El Paso County',
          status: 'clear',
          statusLabel: 'No Active Alerts',
          desc: 'No active hazard zones reported by PPROEM at this time.',
          coords: [],
          center: [38.835, -104.821],
          issued: null,
          affected: 0
        }];
        isLiveData = true;
        drawZones();
        renderZoneList('active');
        setDataStatus('live-empty');
      }
    } catch (err) {
      console.warn('PPROEM hazard fetch failed, keeping mock data:', err);
      isLiveData = false;
      setDataStatus('demo');
    }
  }

  setDataStatus('loading');
  loadLiveZones();
  setInterval(loadLiveZones, REFRESH_MS);

  // Expose handlers used by inline on* attributes (the IIFE would otherwise hide them).
  window.handleSearch = handleSearch;
  window.demoSearch = demoSearch;
  window.switchTab = switchTab;
  window.onTabKeydown = onTabKeydown;
  window.closeSubscribe = closeSubscribe;
  window.handleSubscribe = handleSubscribe;
  window.focusZone = focusZone;
  window.openSubscribe = openSubscribe;
})();
